import{_ as a,c as s,o as i,a5 as p}from"./chunks/framework.DwbewbAn.js";const n="/assets/1459179-20191127201229189-2078130226.yU7EEDmk.png",t="/assets/1459179-20191127201301931-112939757.CViQwjL0.png",e="/assets/1010383-20181125125028200-674394381.BxWwu6yM.jpg",l="/assets/1010383-20181125125131772-422512783.D4r0HKYi.jpg",r="/assets/1010383-20181125125255513-597427685.CnZ3M1G6.jpg",h="/assets/1010383-20181125125322808-1073086489.Su_X_OwX.jpg",o="/assets/1010383-20181125125352002-1327823573.Cv33tezk.jpg",k="/assets/1010383-20181125125412737-1589162849.DNnN1YSH.jpg",c="/assets/1010383-20181125125436843-1347485482.ze7yqsdY.jpg",d="/assets/1010383-20181125125520129-1709188591.tsL6HuGf.jpg",q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/算法/排序/堆排序/堆排序.md","filePath":"packages/doc/src/算法/排序/堆排序/堆排序.md","lastUpdated":1702458087000}'),g={name:"doc/算法/排序/堆排序/堆排序.md"},m=p('<p>在实际应用中，我们经常需要从一组对象中查找<strong>最大值</strong>或<strong>最小值</strong>。当然我们可以每次都先排序，然后再进行查找，但是这种做法效率很低。哪么有没有一种特殊的数据结构，可以高效率的实现我们的需求呢，答案就是<strong>堆(heap)</strong></p><p>堆分为最小堆和最大堆，它们的性质相似，我们以最小堆为例子。</p><h3 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ul><li>是一棵完全二叉树</li></ul><blockquote><p>如果一颗二叉树的任何结点，或者是树叶，或者左右子树均非空，则这棵二叉树称做满二叉树（full binary tree）</p><p>如果一颗二叉树最多只有最下面的两层结点度数可以小于2，并且最下面一层的结点都集中在该层最左边的连续位置上，则此二叉树称做完全二叉树（complete binary tree）</p></blockquote><p><img src="'+n+`" alt="满二叉树和完全二叉树"></p><ul><li>局部有序</li></ul><p>最小堆对应的完全二叉树中所有结点的值均不大于其左右子结点的值，且一个结点与其兄弟之间没有必然的联系</p><blockquote><p>二叉搜索树中，左子 &lt; 父 &lt; 右子</p></blockquote><h3 id="存储结构" tabindex="-1">存储结构 <a class="header-anchor" href="#存储结构" aria-label="Permalink to &quot;存储结构&quot;">​</a></h3><p>由于堆是一棵完全二叉树，所以我们可以用顺序结构来存储它，只需要计算简单的代数表达式，就能够非常方便的查找某个结点的父结点和子节点，既避免了使用指针来保持结构，又能高效的执行相应操作。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>结点i的左子结点为2xi+1,右子结点为2xi+2</span></span>
<span class="line"><span>结点i的父节点为(i-1)/2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+t+'" alt="存储结构"></p><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 本例为最小堆</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 最大堆只需要修改less函数即可</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Heap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> []</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">h </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Heap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">swap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">j</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	h[i], h[j] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> h[j], h[i]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">h </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Heap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">less</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">j</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> h[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> h[j]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>如上所示，我们使用slice来存储我们的数据，为了后续方便我们在此定义了 <code>swap</code> 和 <code>less</code> 函数，分别用来交换两个结点和比较大小。</p><h4 id="_1、堆排序时间复杂度" tabindex="-1">1、堆排序时间复杂度 <a class="header-anchor" href="#_1、堆排序时间复杂度" aria-label="Permalink to &quot;1、堆排序时间复杂度&quot;">​</a></h4><p>堆排序的时间复杂度是O(N*lgN)。</p><p>假设被排序的数列中有N个数。遍历一趟的时间复杂度是O(N)，需要遍历多少次呢？</p><p>堆排序是采用的二叉堆进行排序的，二叉堆就是一棵二叉树，它需要遍历的次数就是二叉树的深度，而根据完全二叉树的定义，它的深度至少是lg(N+1)。最多是多少呢？由于二叉堆是完全二叉树，因此，它的深度最多也不会超过lg(2N)。因此，遍历一趟的时间复杂度是O(N)，而遍历次数介于lg(N+1)和lg(2N)之间；因此得出它的时间复杂度是O(N*lgN)。</p><h4 id="_2、堆排序稳定性" tabindex="-1">2、堆排序稳定性 <a class="header-anchor" href="#_2、堆排序稳定性" aria-label="Permalink to &quot;2、堆排序稳定性&quot;">​</a></h4><p>堆排序是不稳定的算法，它不满足稳定算法的定义。它在交换数据的时候，是比较父结点和子节点之间的数据，所以，即便是存在两个数值相等的兄弟节点，它们的相对顺序在排序也可能发生变化。</p><p>算法稳定性 -- 假设在数列中存在a[i]=a[j]，若在排序之前，a[i]在a[j]前面；并且排序之后，a[i]仍然在a[j]前面。则这个排序算法是稳定的！</p><h4 id="_3、示例" tabindex="-1">3、示例 <a class="header-anchor" href="#_3、示例" aria-label="Permalink to &quot;3、示例&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>// golang``//堆排序``//s[0]不用，实际元素从角标1开始``//父节点元素大于子节点元素``//左子节点角标为2*k``//右子节点角标为2*k+1``//父节点角标为k/2``func` `HeapSort(s []int) {``  ``N := len(s) - 1 ``//s[0]不用，实际元素数量和最后一个元素的角标都为N``  ``//构造堆``  ``//如果给两个已构造好的堆添加一个共同父节点，``  ``//将新添加的节点作一次下沉将构造一个新堆，``  ``//由于叶子节点都可看作一个构造好的堆，所以``  ``//可以从最后一个非叶子节点开始下沉，直至``  ``//根节点，最后一个非叶子节点是最后一个叶子``  ``//节点的父节点，角标为N/2``  ``for` `k := N / 2; k &gt;= 1; k-- {``    ``sink(s, k, N)``  ``}``  ``//下沉排序``  ``for` `N &gt; 1 {``    ``swap(s, 1, N) ``//将大的放在数组后面，升序排序``    ``N--``    ``sink(s, 1, N)``  ``}``}`` ` `//下沉（由上至下的堆有序化）``func` `sink(s []int, k, N int) {``  ``for` `{``    ``i := 2 * k``    ``if` `i &gt; N { ``//保证该节点是非叶子节点``      ``break``    ``}``    ``if` `i &lt; N &amp;&amp; s[i+1] &gt; s[i] { ``//选择较大的子节点``      ``i++``    ``}``    ``if` `s[k] &gt;= s[i] { ``//没下沉到底就构造好堆了``      ``break``    ``}``    ``swap(s, k, i)``    ``k = i``  ``}``}`` ` `func` `swap(s []int, i int, j int) {``  ``s[i], s[j] = s[j], s[i]``}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p></p><h4 id="_4、算法流程分析" tabindex="-1">4、算法流程分析 <a class="header-anchor" href="#_4、算法流程分析" aria-label="Permalink to &quot;4、算法流程分析&quot;">​</a></h4><p>堆排序(Heap Sort)是指利用堆这种数据结构所设计的一种排序算法。</p><p>因此，学习堆排序之前，有必要了解堆！若读者不熟悉堆，建议先了解<a href="http://www.cnblogs.com/skywang12345/p/3610187.html" target="_blank" rel="noreferrer">堆</a>(建议可以通过<a href="http://www.cnblogs.com/skywang12345/p/3610187.html" target="_blank" rel="noreferrer">二叉堆</a>，<a href="http://www.cnblogs.com/skywang12345/p/3638327.html" target="_blank" rel="noreferrer">左倾堆</a>，<a href="http://www.cnblogs.com/skywang12345/p/3638493.html" target="_blank" rel="noreferrer">斜堆</a>，<a href="http://www.cnblogs.com/skywang12345/p/3655900.html" target="_blank" rel="noreferrer">二项堆</a>或<a href="http://www.cnblogs.com/skywang12345/p/3659060.html" target="_blank" rel="noreferrer">斐波那契堆</a>等文章进行了解)，然后再来学习本章。</p><p>我们知道，堆分为&quot;最大堆&quot;和&quot;最小堆&quot;。最大堆通常被用来进行&quot;升序&quot;排序，而最小堆通常被用来进行&quot;降序&quot;排序。</p><p>鉴于最大堆和最小堆是对称关系，理解其中一种即可。本文将对最大堆实现的升序排序进行详细说明。</p><p><strong>最大堆进行升序排序的基本思想：</strong></p><p>① 初始化堆：将数列a[1...n]构造成最大堆。</p><p>② 交换数据：将a[1]和a[n]交换，使a[n]是a[1...n]中的最大值；然后将a[1...n-1]重新调整为最大堆。 接着，将a[1]和a[n-1]交换，使a[n-1]是a[1...n-1]中的最大值；然后将a[1...n-2]重新调整为最大值。 依次类推，直到整个数列都是有序的。</p><p>下面，通过图文来解析堆排序的实现过程。注意实现中用到了&quot;数组实现的二叉堆的性质&quot;。</p><p>在第一个元素的索引为 0 的情形中：</p><p>性质一：索引为i的左孩子的索引是 (2*i+1);</p><p>性质二：索引为i的左孩子的索引是 (2*i+2);</p><p>性质三：索引为i的父结点的索引是 floor((i-1)/2);</p><p><img src="'+e+'" alt="img"></p><p><img src="https://note.youdao.com/src/A116F54AF6F54BFBBF1FA6F21B61B2B5" alt="img"></p><p>例如，对于最大堆{110,100,90,40,80,20,60,10,30,50,70}而言：索引为0的左孩子的所有是1；索引为0的右孩子是2；索引为8的父节点是3。</p><p>下面演示heap_sort_asc(a, n)对a={20,30,90,40,70,110,60,10,100,50,80}, n=11进行堆排序过程。下面是数组a对应的初始化结构：</p><p><img src="https://note.youdao.com/src/27843BD505814308A58BFE36F2626CF1" alt="img"></p><p><img src="'+l+'" alt="img"></p><h5 id="_1-初始化堆" tabindex="-1">1 初始化堆 <a class="header-anchor" href="#_1-初始化堆" aria-label="Permalink to &quot;1 初始化堆&quot;">​</a></h5><p>在堆排序算法中，首先要将待排序的数组转化成二叉堆。</p><p>下面演示将数组{20,30,90,40,70,110,60,10,100,50,80}转换为最大堆{110,100,90,40,80,20,60,10,30,50,70}的步骤。</p><p>1.1 i=11/2-1，即i=4</p><p><img src="'+r+'" alt="img"></p><p><img src="https://note.youdao.com/src/459515354A1048B894D537E55176D94E" alt="img"></p><p>上面是maxheap_down(a, 4, 9)调整过程。maxheap_down(a, 4, 9)的作用是将a[4...9]进行下调；a[4]的左孩子是a[9]，右孩子是a[10]。调整时，选择左右孩子中较大的一个(即a[10])和a[4]交换。</p><p>1.2 i=3</p><p><img src="'+h+'" alt="img"></p><p><img src="https://note.youdao.com/src/C96F2A98EF904FC7A3915FE70CBD306C" alt="img"></p><p>上面是maxheap_down(a, 3, 9)调整过程。maxheap_down(a, 3, 9)的作用是将a[3...9]进行下调；a[3]的左孩子是a[7]，右孩子是a[8]。调整时，选择左右孩子中较大的一个(即a[8])和a[4]交换。</p><p>1.3 i=2</p><p><img src="https://note.youdao.com/src/40A31FFE944044869FDBCA6E94448ED3" alt="img"></p><p><img src="'+o+'" alt="img"></p><p>上面是maxheap_down(a, 2, 9)调整过程。maxheap_down(a, 2, 9)的作用是将a[2...9]进行下调；a[2]的左孩子是a[5]，右孩子是a[6]。调整时，选择左右孩子中较大的一个(即a[5])和a[2]交换。</p><p>1.4 i=1</p><p><img src="https://note.youdao.com/src/2A2710F7DDDF4A1BBFAE7C2A5CB3FDDA" alt="img"></p><p><img src="'+k+'" alt="img"></p><p>上面是maxheap_down(a, 1, 9)调整过程。maxheap_down(a, 1, 9)的作用是将a[1...9]进行下调；a[1]的左孩子是a[3]，右孩子是a[4]。调整时，选择左右孩子中较大的一个(即a[3])和a[1]交换。交换之后，a[3]为30，它比它的右孩子a[8]要大，接着，再将它们交换。</p><p>1.5 i=0</p><p><img src="https://note.youdao.com/src/89FA229C7557469C80A4C386CF1B13A2" alt="img"></p><p><img src="'+c+'" alt="img"></p><p>上面是maxheap_down(a, 0, 9)调整过程。maxheap_down(a, 0, 9)的作用是将a[0...9]进行下调；a[0]的左孩子是a[1]，右孩子是a[2]。调整时，选择左右孩子中较大的一个(即a[2])和a[0]交换。交换之后，a[2]为20，它比它的左右孩子要大，选择较大的孩子(即左孩子)和a[2]交换。</p><p>调整完毕，就得到了最大堆。此时，数组{20,30,90,40,70,110,60,10,100,50,80}也就变成了{110,100,90,40,80,20,60,10,30,50,70}。</p><h5 id="第2部分-交换数据" tabindex="-1">第2部分 交换数据 <a class="header-anchor" href="#第2部分-交换数据" aria-label="Permalink to &quot;第2部分 交换数据&quot;">​</a></h5><p>在将数组转换成最大堆之后，接着要进行交换数据，从而使数组成为一个真正的有序数组。</p><p>交换数据部分相对比较简单，下面仅仅给出将最大值放在数组末尾的示意图。</p><p><img src="https://note.youdao.com/src/BA14074CB2AA41A2B5664DC0AB77F4D1" alt="img"></p><p>上面是当n=10时，交换数据的示意图。</p><p><img src="'+d+'" alt="img"></p><p>当n=10时，首先交换a[0]和a[10]，使得a[10]是a[0...10]之间的最大值；然后，调整a[0...9]使它称为最大堆。交换之后：a[10]是有序的！</p><p>当n=9时， 首先交换a[0]和a[9]，使得a[9]是a[0...9]之间的最大值；然后，调整a[0...8]使它称为最大堆。交换之后：a[9...10]是有序的！</p><p>...</p><p>依此类推，直到a[0...10]是有序的。</p>',79),u=[m];function E(b,_,y,F,w,A){return i(),s("div",null,u)}const B=a(g,[["render",E]]);export{q as __pageData,B as default};
